#include <stdint.h>
#include <vx_print.h>
#include <vx_intrinsics.h>

int main() {
  int val = (int)(vx_num_threads());
  vx_printf("SIMX_RESULT=%d\n", val);
  vx_printf("SIMX_EXPECTED=%d\n", val);
  vx_printf("SIMX_CYCLES=%d\n", 1);
  vx_printf("Passed! result matched expected\n");
  return 0;
}

